colsdata.lang:
// BO columns
paging: true,
scrollX: true,
//scrollY: 300,
//scrollCollapse: true,
order: [[2, "asc" ]], // order column descending
"columnDefs": [
    {
        "orderable": false,
        "targets": [3, 4],
    },
    {
        width: 100,
        targets: [3,4,6],
    },
    {
        width: 300,
        targets: [0],
    },
],
//asStripeClasses: [] // disable zebra coloring of rows
//bSortClasses: false // disable coloring of sorted column
// l - length changing input control
// f - filtering input
// t - The table!
// i - Table information summary
// p - pagination control
// r - processing display element
//dom: 'fltipr',
dom: "<'row dom_wrapper fh-fixedHeader'fl>" +
    "<'row'<'col-sm col-md'tr>>" +
    "<'row'<'col-sm col-md'p><'col-sm col-md'>i>",
pageLength: 20,
lengthMenu: [[10, 20, 100, 250, 500, 1000], [10, 20, 100, 250, 500, 1000]],
columns: [
	{
        data: null,
        render: function (data, type, row) {
            if (row.domain != null) {
                return row.domain;
            }
            else if (row.server != null) {
                return row.server;
            }
            else {
                return '';
            }
        }
	},
	{
        data: null,
        render: function (data, type, row) {
            if (row.aliases != null) {
                return row.aliases;
            }
            else {
                return '-';
            }
        }
	},
	{
        data: null,
        render: function (data, type, row) {
            return '<a href="' + row.path + '/manage" target="_blank">' + row.breadcrumbs + '</a>';
        }
	},
	{
        data: null,
        render: function (data, type, row) {
            if (row.attr_dc_type != null) {
                return row.attr_dc_type;
            }
            else {
                return '-'
            }
        }
	},
	{
        data: null,
        render: function (data, type, row) {
            if (row.workflow != null) {
                return row.workflow;
            }
            else {
                return '-';
            }
            if (row.workflow_nodes != null) {
                return row.workflow_nodes;
            }
            else {
                return '';
            }
        }
	},
/*	{
        data: null,
        render: function (data, type, row) {
            if (row.robots != null) {
                return row.robots;
            }
            else {
                return '-';
            }
        }
	},*/
	{
        data: null,
        render: function (data, type, row) {
            if (row.comments != null) {
                return row.comments;
            }
            else {
                return '-';
            }
        }
	},
	{
        data: null,
        render: function (data, type, row) {
            if (row.etracker != null) {
                return row.etracker;
            }
            else {
                return '-';
            }
        }
	},
],
responsive: false, /*{
	details: {
		renderer: function(api, rowIdx) {
            // Select hidden columns for the given row
            var data = api.cells(rowIdx, ':hidden').eq(0).map(function(cell) {
                var header = $(api.column(cell.column).header());
                return '<tr>'+
                        '<td>'+
                            header.text() + ':' +
                        '</td> ' +
                        '<td>' +
                            api.cell(cell).data() +
                        '</td>' +
                    '</tr>';
            }).toArray().join('');

            return data ? $('<table/>').append(data) : false;
        }
	}
},*/
// https://datatables.net/examples/api/multi_filter_select.html
initComplete: function () {
    i = 0;
    this.api().columns().every(function() {
        var column = this;
        var column_filter_for = [3, 4];
        if (column_filter_for.includes(i)) {
            var select = $('<select><option value=""></option></select>')
                .appendTo( $(column.header()) )
                .on('change', function () {
                    var val = $.fn.dataTable.util.escapeRegex(
                        $(this).val()
                    );
                    column
                        .search( val ? '^'+val+'$' : '', true, false )
                        .draw();
                } );
            column.data().unique().sort().each( function ( d, j ) {
                select.append('<option value="'+d+'">'+d+'</option>')
            } );
        }
        else {
            column.text = '';
        }
        i++;
    } );
},
/* https://github.com/gyrocode/jquery-datatables-alphabetSearch
alphabetSearch: {
    column: 1
}, */

